/**
 * Polyglot Scanner × Checkpoint Homology Bridge
 *
 * Maps per-function polyglot scanner output (PolyglotFunctionAnalysis)
 * into the universal CheckpointedSystem algebra, so that every project
 * gets a formally-verified health diagnosis computed from actual code
 * topology — not estimates, not heuristics, but real beta1 and deficit
 * from tree-sitter ASTs fed through Betty.
 *
 * The bridge closes the loop:
 *   Lean proves the algebra →
 *   scanner computes the inputs →
 *   bridge maps to algebra →
 *   theorems guarantee the diagnosis is sound →
 *   treatment planner sequences the repair →
 *   repair module injects VENT paths →
 *   re-scan verifies the cure →
 *   loop terminates at TopologicalSaturation (GraphSabbath)
 *
 * Formal backing (6 Lean modules, zero sorry):
 *   CheckpointHomology.lean — self_repair_completeness
 *   PolyglotCheckpointFunctor.lean — scanner → algebra preserves conservation
 *   CancerTreatments.lean — gate-first sequencing, cascade amplification
 *   AgileGnosisTopology.lean — failure as fuel, waterfall collapse proof
 *   EschatonTopology.lean — termination: saturation halts engine
 *   UniversalRepairTopology.lean — 4 mechanisms minimally sufficient,
 *     isomorphic across git/psyche/ecology/macroeconomics
 *
 * @module @a0n/gnosis/polyglot-checkpoint-bridge
 */

import type {
  PolyglotAnalysisResult,
  PolyglotFunctionAnalysis,
  PolyglotDiagnosticFinding,
  PolyglotGhostMassLedger,
} from './polyglot-bridge';
import {
  type CheckpointedSystem,
  type Diagnosis,
  type HealthStatus,
  diagnose,
  godFormulaWeight,
  forecastRepair,
  forecastNeglect,
} from './checkpoint-substrates';
import {
  type GnosisVoidDimension,
  type GnosisVoidDimensionAssessment,
  assessVoidDimension,
} from './void-dimensions';
import {
  type BrunnianResult,
  detectBrunnianCoupling,
  type TopologyModule,
} from './brunnian';

// ═══════════════════════════════════════════════════════════════════════
// Scan Aggregation Types
// ═══════════════════════════════════════════════════════════════════════

/**
 * Four-way health classification for a function.
 *
 *   active  — internal feedback (loops, VENT paths, rejection channels)
 *   covered — no internal feedback but has external coverage (tests)
 *   deaf    — has branching but no feedback of any kind (actually sick)
 *   silent  — pure linear, no branching, no need for feedback
 *
 * Only DEAF functions are actually sick and need repair.
 * Silent functions are healthy by nature. Covered functions are
 * healthy by external verification. Active functions are healthy
 * by internal structure.
 */
export type FunctionHealthClass = 'active' | 'covered' | 'deaf' | 'silent';

/**
 * Per-function metrics extracted from the polyglot scanner + Betty.
 */
export interface FunctionMetrics {
  /** Function name from the scanner. */
  functionName: string;
  /** Source file path. */
  filePath: string;
  /** First Betti number — essential loops, learning capacity. */
  beta1: number;
  /** Topological deficit from Betty's deficit analysis. */
  deficit: number;
  /** Buley complexity measure (topology entropy). */
  buleyMeasure: number;
  /** Void dimensions — FORK branch count. */
  voidDimensions: number;
  /** God Formula weight: w = R - min(v, R) + 1 where R = beta1 + deficit. */
  godWeight: number;
  /** Ghost mass — leaked/unaccounted topology mass. */
  ghostMass: number;
  /** Diagnostic finding count. */
  diagnosticCount: number;
  /** Whether beta1 > 0 (can learn from feedback). */
  isLearning: boolean;
  /** Landauer heat from Betty. */
  landauerHeat: number;
  /** Whether the function has FORK/FOLD branching in its topology. */
  hasBranching: boolean;
  /** Whether a test file exists that covers this function. */
  hasTestCoverage: boolean;
  /**
   * Four-way health classification:
   *   active  — has internal feedback (beta1 > 0)
   *   covered — no internal feedback but has test coverage
   *   deaf    — branching, no feedback, no tests (ACTUALLY SICK)
   *   silent  — no branching at all (healthy by simplicity)
   */
  healthClass: FunctionHealthClass;
}

/**
 * A TwoTermComplex in TypeScript — mirrors CheckpointHomology.TwoTermComplex in Lean.
 * rank1 = active (living), rank0 = destroyed (boundary).
 */
export interface TwoTermComplex {
  rank1: number;
  rank0: number;
}

/**
 * Three independent chain complexes for void dimensions.
 * Each dimension is a separate TwoTermComplex.
 * The composite is the direct sum (rank1_total = sum of rank1s, same for rank0).
 *
 * @see THM-DIRECT-SUM-RANK1-ADDITIVE — rank1 is additive under direct sum
 * @see THM-DIRECT-SUM-RANK0-ADDITIVE — rank0 is additive under direct sum
 */
export interface VoidDimensionProfile {
  /** Inter-module coupling stress. */
  cross_file: TwoTermComplex;
  /** Load-dependent timing stress. */
  temporal: TwoTermComplex;
  /** Query/wire crossing stress. */
  data_plane: TwoTermComplex;
  /** Direct sum of all three dimensions. */
  composite: TwoTermComplex;
  /** Per-dimension assessments from void-dimensions.ts. */
  assessments: GnosisVoidDimensionAssessment[];
}

/**
 * Brunnian coupling interference term for a project.
 */
export interface BrunnianInterference {
  /** Detected Brunnian couplings. */
  couplings: BrunnianResult[];
  /** Total emergent coupling strength across all n-wise knots. */
  totalEmergentStrength: number;
  /** Number of genuine Brunnian links found. */
  brunnianCount: number;
  /** Module IDs involved in at least one Brunnian coupling. */
  affectedModules: string[];
  /**
   * Interference penalty: additional destroyed channels due to
   * Brunnian coupling. When a Brunnian-coupled module is destroyed,
   * its partners are partially degraded.
   */
  interferencePenalty: number;
}

/**
 * Purity profile for a project — classifies functions by topology complexity.
 *
 * A "pure" function has no FORK/FOLD edges (linear Entry→Process→Return).
 * A "branching" function has FORK/FOLD but no cycles (if/else/switch).
 * A "looping" function has PROCESS back-edges (for/while cycles).
 *
 * The purity ratio determines the expected deafness baseline:
 * a library of pure mappers SHOULD have high sigma — pure functions
 * are correctly deaf because they don't iterate or reject.
 *
 * Health thresholds are shifted by purity:
 *   adjustedSigma = rawSigma - purityBaseline
 *   where purityBaseline = pureRatio × 0.8
 *
 * This way, a project with 90% pure functions gets a baseline of 0.72
 * subtracted from its raw sigma before health classification.
 */
export interface PurityProfile {
  /** Functions with no FORK, no loops — simple transformations. */
  pureFunctions: number;
  /** Functions with FORK/FOLD but no loops — branching logic. */
  branchingFunctions: number;
  /** Functions with PROCESS back-edges — iterative logic. */
  loopingFunctions: number;
  /** Total functions classified. */
  totalFunctions: number;
  /** Ratio of pure functions to total (0..1). */
  purityRatio: number;
  /**
   * Expected sigma baseline from purity alone.
   * High-purity projects get a higher baseline (more tolerance).
   * purityBaseline = purityRatio × 0.8
   */
  purityBaseline: number;
  /**
   * Adjusted sigma: rawSigma - purityBaseline, clamped to [0, 1].
   * This is the "real" sickness after accounting for expected purity.
   */
  adjustedSigma: number;
  /**
   * Health classification using adjusted sigma instead of raw sigma.
   */
  adjustedHealth: HealthStatus;
}

/**
 * Aggregated scan result for an entire project.
 */
export interface ProjectScanResult {
  /** Project name / identifier. */
  projectName: string;
  /** Per-function metrics. */
  functions: FunctionMetrics[];
  /** Total function count. */
  functionCount: number;
  /** Sum of beta1 across all functions. */
  totalBeta1: number;
  /** Sum of deficit across all functions. */
  totalDeficit: number;
  /** Sum of God Formula weights. */
  totalGodWeight: number;
  /** Maximum God Formula weight (worst single function). */
  maxGodWeight: number;
  /** Functions with godWeight > hotspot threshold. */
  hotspotCount: number;
  /** Sum of ghost mass across all functions. */
  totalGhostMass: number;
  /** Sum of void dimensions across all functions. */
  totalVoidDimensions: number;
  /** Sum of Buley measures across all functions. */
  totalBuleyMeasure: number;
  /** Total diagnostic findings. */
  totalDiagnostics: number;
  /** Files analyzed. */
  filesAnalyzed: number;
  /** Errors encountered during analysis. */
  errors: string[];
}

/**
 * Full checkpoint profile for a project — the bridge output.
 */
export interface ProjectCheckpointProfile {
  /** Project name. */
  projectName: string;
  /** Raw scan aggregation. */
  scan: ProjectScanResult;
  /** Functions with beta1 > 0 (active rejection channels). */
  activeChannels: number;
  /** Functions with beta1 = 0 (destroyed rejection channels). */
  destroyedChannels: number;
  /** The CheckpointedSystem mapped from the scan. */
  system: CheckpointedSystem;
  /** Diagnosis from checkpoint-substrates.ts. */
  diagnosis: Diagnosis;
  /**
   * Real sigma: normalized stress from actual code topology.
   * sicknessFraction from the CheckpointedSystem.
   */
  sigma: number;
  /**
   * Top functions ordered by God Formula weight (highest = fix first).
   * These have the most deficit and will give the most beta1 gain per repair.
   */
  repairOrdering: RepairCandidate[];
  /**
   * Forecast: what happens if we restore the top candidate.
   */
  forecastIfRepaired: CheckpointedSystem;
  /**
   * Forecast: what happens if we lose one more channel.
   */
  forecastIfNeglected: CheckpointedSystem;
  /**
   * Void dimension profile: 3 independent chain complexes.
   * Shows WHERE the disease lives, not just THAT it exists.
   */
  voidProfile: VoidDimensionProfile;
  /**
   * Brunnian coupling interference.
   * n-wise emergent knots that pairwise analysis misses.
   */
  brunnianInterference: BrunnianInterference;
  /**
   * Purity profile — classifies functions as pure/branching/looping.
   * Used to calibrate health thresholds for the project type.
   */
  purityProfile: PurityProfile;
}

/**
 * A function ranked for repair priority by the God Formula.
 */
export interface RepairCandidate {
  functionName: string;
  filePath: string;
  godWeight: number;
  beta1: number;
  deficit: number;
  ghostMass: number;
}

